"""Format objects for structured data ingestion.

Format objects encapsulate inter-file relationships and normalization
logic for domain-specific dataset layouts (e.g. COCO, YOLO).

Each format class exposes a ``normalize()`` method that yields
``dict[str, list]`` batches compatible with ``Client.ingest()``.

Usage:
    from deeplake.managed.formats import CocoPanoptic

    client.ingest("panoptic", format=CocoPanoptic(
        images_dir="coco/train2017",
        masks_dir="coco/panoptic_train2017",
        annotations="coco/annotations/panoptic_train2017.json",
    ))
"""

from .base import Format


def __getattr__(name: str):
    if name == "Coco":
        from .coco import Coco
        return Coco
    if name == "CocoPanoptic":
        from .coco_panoptic import CocoPanoptic
        return CocoPanoptic
    if name in ("LeRobotTasks", "LeRobotFrames", "LeRobotEpisodes"):
        from . import lerobot
        return getattr(lerobot, name)
    raise AttributeError(f"module {__name__!r} has no attribute {name!r}")


__all__ = [
    "Format",
    "Coco",
    "CocoPanoptic",
    "LeRobotTasks",
    "LeRobotFrames",
    "LeRobotEpisodes",
]
